import { Component, OnInit, OnDestroy, inject, ViewChild, ElementRef, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { catchError, filter, first, of, Subject, switchMap, takeUntil } from 'rxjs';

import { RestaurantPublicService, PublicRestaurant } from '../../services/restaurant-public.service';
import { GeographyService } from '../../services/Base/geography.service';
import { LucideAngularModule } from 'lucide-angular';
import { TutorialService, TutorialStep, TutorialType } from '../../services/tutorial.service';
import { AuthService } from '../../services/Base/auth.service';
import { PushNotificationService } from '../../services/push-notification.service';

@Component({
  selector: 'app-profile',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, LucideAngularModule, FormsModule],
  templateUrl: './profile.html',
  styleUrls: ['./profile.css']
})
export class Profile implements OnInit, OnDestroy {
  private fb = inject(FormBuilder);
  private restaurantService = inject(RestaurantPublicService);
  private geographyService = inject(GeographyService);
  public tutorialService = inject(TutorialService);
  private authService = inject(AuthService);
  public pushService = inject(PushNotificationService);
  public cdr = inject(ChangeDetectorRef);

  pushPermission: NotificationPermission | 'unsupported' = 'default';
  hasActivePush = false;
  pushLoading = false;
  isOwner = false;

  private destroy$ = new Subject<void>();

  profileForm!: FormGroup;
  loading = false;
  logoPreview?: string;
  restaurant: PublicRestaurant | null = null;

  provinces: any[] = [];
  regions: string[] = [];
  filteredProvinces: any[] = [];

  @ViewChild('logoInput') logoInput!: ElementRef<HTMLInputElement>;

ngOnInit() {
  this.pushPermission = this.pushService.isSupported()
    ? Notification.permission
    : 'unsupported';

  this.authService.currentUser$
    .pipe(
      filter(user => !!user),
      first(),
      switchMap(() => this.pushService.hasActiveSubscription()),
      catchError(err => {
        console.error('Errore nel controllo notifiche:', err);
        return of(false);
      }),
      takeUntil(this.destroy$)
    )
    .subscribe(active => {
      this.hasActivePush = active;
      console.log('hasActivePush after auth:', active);
    });

  this.initForm();
  this.loadProvinces();
  this.loadRestaurantData();
}


  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private initForm() {
    this.profileForm = this.fb.group({
      name: ['', [Validators.required, Validators.minLength(2)]],
      description: [''],
      address: ['', Validators.required],
      phone: ['', [Validators.required, Validators.pattern(/^[\+\d\s\-\(\)]{8,20}$/)]],
      email: ['', [Validators.required, Validators.email]],
      region: [''],
      province: ['']
    });
  }

  private async loadProvinces() {
    this.geographyService.getFilteredProvinces()
      .pipe(takeUntil(this.destroy$))
      .subscribe(provinces => {
        this.provinces = provinces;
        this.regions = [...new Set(provinces.map(p => p.region))]
          .filter(r => r !== 'Tutte')
          .sort();
      });
  }

  private async loadRestaurantData() {
    this.loading = true;
    try {
      this.restaurant = await this.restaurantService.loadCurrentRestaurant();
      if (this.restaurant) {
        this.patchForm(this.restaurant);
        this.logoPreview = this.restaurant.logo_url || undefined;

        // Verifica se l'utente corrente è il proprietario
        const currentUser = this.authService.currentUserValue;
        this.isOwner = currentUser ? this.restaurant.owner_id === currentUser.id : false;

        // Disabilita il form se non è il proprietario
        if (!this.isOwner) {
          this.profileForm.disable();
        }
      }
    } catch (error) {
      console.error('Errore caricamento profilo:', error);
    } finally {
      this.loading = false;
    }
  }

  private patchForm(restaurant: PublicRestaurant) {
    const provinceCode = restaurant.province;
    let regionFromProvince = '';
    if (provinceCode && this.provinces.length) {
      const province = this.provinces.find(p => p.code === provinceCode);
      if (province) {
        regionFromProvince = province.region;
        this.filterProvincesByRegion(regionFromProvince);
      }
    }

    this.profileForm.patchValue({
      name: restaurant.name,
      description: restaurant.description || '',
      address: restaurant.address,
      phone: restaurant.phone,
      email: restaurant.email,
      region: regionFromProvince,
      province: provinceCode || ''
    });
  }

  private filterProvincesByRegion(region: string) {
    this.filteredProvinces = region
      ? this.provinces.filter(p => p.region === region)
      : [];

    // GESTIONE STATO ABILITATO/DISABILITATO
    const provinceControl = this.profileForm.get('province');

    if (this.filteredProvinces.length > 0) {
      provinceControl?.enable(); // Abilita se ci sono province
    } else {
      provinceControl?.disable(); // Disabilita se la lista è vuota
      this.profileForm.patchValue({ province: '' });
    }
  }

  onRegionChange(event: Event) {
    const region = (event.target as HTMLSelectElement).value;
    this.filterProvincesByRegion(region);
  }

  onProvinceChange(event: Event) {
    const provinceCode = (event.target as HTMLSelectElement).value;
    if (provinceCode) {
      const province = this.provinces.find(p => p.code === provinceCode);
      if (province) {
        this.profileForm.patchValue({ region: province.region });
        this.filterProvincesByRegion(province.region);
      }
    } else {
      this.profileForm.patchValue({ region: '' });
      this.filteredProvinces = [];
    }
  }

  triggerLogoInput() {
    this.logoInput.nativeElement.click();
  }

  async onLogoSelected(event: Event) {
    const input = event.target as HTMLInputElement;
    if (!input.files?.length) return;
    const file = input.files[0];

    if (file.size > 5 * 1024 * 1024) {
      alert('Il file non può superare i 5MB');
      return;
    }
    if (!file.type.startsWith('image/')) {
      alert('Seleziona un file immagine');
      return;
    }

    this.loading = true;
    try {
      const publicUrl = await this.restaurantService.uploadLogo(file);
      if (publicUrl) {
        this.logoPreview = publicUrl;
        alert('Logo caricato con successo!');
      }
    } catch (error: any) {
      alert('Errore caricamento logo: ' + error.message);
    } finally {
      this.loading = false;
      input.value = '';
    }
  }

  async removeLogo() {
    if (!this.logoPreview) return;
    if (!confirm('Rimuovere il logo?')) return;

    this.loading = true;
    try {
      const success = await this.restaurantService.removeLogo();
      if (success) {
        this.logoPreview = undefined;
        alert('Logo rimosso');
      }
    } catch (error: any) {
      alert('Errore: ' + error.message);
    } finally {
      this.loading = false;
    }
  }

  async onSubmit() {
    if (!this.isOwner) {
      alert('Non hai i permessi per modificare questo profilo.');
      return;
    }
    if (this.profileForm.invalid) return;

    this.loading = true;
    try {
      const formValue = this.profileForm.value;
      const restaurantId = await this.restaurantService.getCurrentRestaurantId();
      if (!restaurantId) throw new Error('Ristorante non trovato');

      // Prepara i dati base
      const updateData: any = {
        name: formValue.name,
        description: formValue.description || null,
        address: formValue.address,
        phone: this.cleanPhoneNumber(formValue.phone),
        email: formValue.email,
        province: formValue.province || null
      };

      // Geocoding dell'indirizzo (solo se presenti entrambi)
      if (formValue.address && formValue.province) {
        const coords = await this.restaurantService.geocodeAddress(formValue.address, formValue.province);
        if (coords) {
          updateData.latitude = coords.lat;
          updateData.longitude = coords.lng;
          console.log('✅ Coordinate ottenute:', coords);
        } else {
          console.warn('⚠️ Geocoding fallito, procedo senza coordinate');
          // Avvisa l'utente (opzionale)
          alert('Indirizzo non geolocalizzato automaticamente. Puoi inserire le coordinate manualmente in seguito.');
        }
      }

      const success = await this.restaurantService.updateRestaurant(restaurantId, updateData);
      if (success) {
        alert('Profilo aggiornato!');
        await this.loadRestaurantData(); // ricarica i dati aggiornati
      }
    } catch (error: any) {
      alert('Errore salvataggio: ' + error.message);
    } finally {
      this.loading = false;
    }
  }

  private cleanPhoneNumber(phone: string): string {
    if (!phone) return '';
    return phone.startsWith('+') ? '+' + phone.substring(1).replace(/\D/g, '') : phone.replace(/\D/g, '');
  }

  // Espone gli step filtrati per il template
  get tutorialSteps(): TutorialStep[] {
    return this.tutorialService.steps();
  }

  get tutorialSections(): TutorialStep[] {
    const context = this.authService.getCurrentContext();
    const allSteps = context === 'staff'
      ? TutorialService.BUSINESS_STEPS
      : TutorialService.CUSTOMER_STEPS;

    // Filtra per permessi (stessa logica di _getVisibleSteps)
    const visibleSteps = allSteps.filter((step: TutorialStep) => {
      if (!step.requiredPermission) return true;
      return this.authService.hasPermission(step.requiredPermission);
    });

    // Mostra solo le sezioni con tooltip (con target o sottostep)
    return visibleSteps.filter((step: TutorialStep) =>
      step.tooltipTarget || (step.subSteps && step.subSteps.length > 0)
    );
  }

  selectedStepId: string | null = null;

  startSelectedTutorial() {
    if (this.selectedStepId) {
      this.tutorialService.startTutorialFromStep(this.selectedStepId, 'single');
    }
  }

  restartFullTutorial() {
    const context = this.authService.getCurrentContext();
    const type: TutorialType = context === 'staff' ? 'business' : 'customer';
    this.tutorialService.restartTutorial(type);
  }

async enablePushNotifications() {
  console.log('A. enablePushNotifications called');
  this.pushLoading = true;
  
  // Timeout di sicurezza — mai restare bloccati
  const timeout = setTimeout(() => {
    this.pushLoading = false;
    this.cdr.detectChanges();
    console.warn('Push timeout — operazione troppo lenta');
  }, 10000);

  try {
    const success = await this.pushService.requestPermissionAndSubscribe();
    console.log('B. Risultato:', success);
    this.pushPermission = Notification.permission;
    this.hasActivePush = success;
    this.cdr.detectChanges();
  } catch (err) {
    console.error('D. Errore in enablePushNotifications:', err);
  } finally {
    clearTimeout(timeout);
    this.pushLoading = false;
    this.cdr.detectChanges();
    console.log('E. pushLoading = false');
  }
}

async disablePushNotifications() {
  console.log('disablePushNotifications - start');
  this.pushLoading = true;
  await this.pushService.revokeConsent();
  this.hasActivePush = false;
  console.log('disablePushNotifications - hasActivePush set to false');
  this.pushLoading = false;
  this.cdr.detectChanges(); // Forza l'aggiornamento
}

get isPushActive(): boolean {
  const active = this.pushPermission === 'granted' && this.hasActivePush;
  console.log('isPushActive computed:', active, 'pushPermission:', this.pushPermission, 'hasActivePush:', this.hasActivePush);
  return active;
}


  async togglePush() {
    if (this.pushLoading) return;

    if (this.isPushActive) {
      await this.disablePushNotifications();
    } else {
      await this.enablePushNotifications();
    }
  }


}